command:
new foundry.applications.api.DialogV2({
  window: { title: "Choose a skill"},
  content: `
    <select id="skillSelect">${Object.entries(CONFIG.PF2E.skills).map(([k, v]) => `<option value='${k}'>${game.i18n.localize(v.label)}</option>`).join(``)}</select>
  `,
  buttons: [{
    action: "generate",
    label: "Generate",
    default: true
  }],
  submit: async (result, dialog) => {
    const select = document.querySelector("#skillSelect");
    window['pf2e-sf2e-extra-feat-slots'].generateSkillParagonFeat(`${select?.value}`)
  }
}).render({force: true })
